const fs = require('fs');
const path = require('path');

function readLogFile(filename) {
    const allowedDirectory = '/path/to/allowed/directory';
    let filePath;

    try {
        filePath = path.resolve(filename);
        if (!filePath.startsWith(allowedDirectory)) {
            throw new Error(`Invalid file path: ${filename}`);
        }
    } catch (error) {
        return `Error reading log file: ${error.message}`;
    }

    try {
        const logContents = fs.readFileSync(filePath, 'utf8');
        return logContents;
    } catch (error) {
        if (error.code === 'ENOENT') {
            return `Log file not found: ${filename}`;
        }
        return `Error reading log file: ${error.message}`;
    }
}

module.exports = readLogFile;